document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("blog-form"),t=new Quill("#editor",{theme:"snow"});e.addEventListener("submit",function(n){n.preventDefault();const o=e.title.value.trim(),s=e.author.value.trim(),a=e.date.value,l=e.summary.value.trim(),i=t.root.innerHTML,r=`${a}-${o.toLowerCase().replace(/[^a-z0-9]+/g,"-")}.html`,c=new Blob([`<!DOCTYPE html>\n<html lang='en'>\n<head>\n  <meta charset='UTF-8'>\n  <meta name='viewport' content='width=device-width, initial-scale=1.0'>\n  <title>${o} | Elemento Blog</title>\n  <link rel='stylesheet' href='../css/style.css'>\n  <link rel='stylesheet' href='../css/themes.css'>\n  <link rel="icon" href="../favicon.ico">\n</head>\n<body class='theme-default'>\n  \x3c!-- Background Canvas for animated gradients --\x3e\n\n  \n  \x3c!-- Navigation --\x3e\n  <div id="navbar-placeholder"></div>\n  \n  <main class='container'>\n    <article class='blog-post'>\n      <h1>${o}</h1>\n      <p class='blog-meta'>By ${s} &mdash; ${a}</p>\n      <p class='blog-summary'>${l}</p>\n      <div class='blog-content'>${i}</div>\n    </article>\n  </main>\n  \n  <footer class='footer'>\n    <div class='container'>\n      <div class='footer-content'>\n        <div class='footer-section'>\n          <img src='../assets/logos/Elemento.svg' alt='Elemento Logo' style='width: 40px; height: 40px; margin-bottom: 1rem;'>\n          <h4>Elemento</h4>\n          <p>Vendor-neutral, high-performance cloud platform that's cost-effective, green, and self-hostable.</p>\n        </div>\n      </div>\n      <div class='footer-bottom'>&copy; 2024 Elemento. All rights reserved. | <a href='../blog.html'>Blog</a></div>\n    </div>\n  </footer>\n  \n  <script src="../js/navbar.js"><\/script>\n  <script src="../js/main.js"><\/script>\n</body>\n</html>`],{type:"text/html"}),d=document.createElement("a");d.href=URL.createObjectURL(c),d.download=r,d.click()})});